import React, { useState } from "react";
import axios from "axios";
import { Line, Bar } from "react-chartjs-2";
import { motion } from "framer-motion";
import AffiliateBanner from "./AffiliateBanner";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend
);

const INDStockDetails = () => {
  const [symbol, setSymbol] = useState("TCS.NS");
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const fetchData = async () => {
    if (!symbol) return;

    setLoading(true);
    setError("");
    try {
      const res = await axios.get(
        `http://localhost:3000/api/stocks/${symbol}`
      );
      console.log("API RESPONSE:", res.data);
      setData(res.data);
    } catch (e) {
      console.error(e);
      setError("Failed to fetch data");
    }
    setLoading(false);
  };

  const formatCurrency = (val) => {
    if (val == null) return "-";
    return `₹${Number(val).toLocaleString("en-IN")}`;
  };

  const formatNumber = (val, decimals = 2) => {
    if (val == null) return "-";
    return Number(val).toFixed(decimals);
  };

  const metricList = [
    { label: "Market Cap", key: "marketCap", currency: true },
    { label: "PE Ratio", key: "peRatio" },
    { label: "ROE (%)", key: "roe" },
    { label: "ROCE (%)", key: "roce" },
    { label: "Dividend Yield (%)", key: "dividendYield" },
    { label: "Book Value", key: "bookValue", currency: true },
    { label: "Face Value", key: "faceValue", currency: true },
    { label: "52 Week High", key: "fiftyTwoWeekHigh", currency: true },
    { label: "52 Week Low", key: "fiftyTwoWeekLow", currency: true }
  ];

  const renderMetric = (label, value, currency = false) => (
    <motion.div
      key={label}
      style={metricCard}
      whileHover={{ scale: 1.05 }}
    >
      <span style={metricLabel}>{label}</span>
      <span style={metricValue}>
        {currency ? formatCurrency(value) : formatNumber(value)}
      </span>
    </motion.div>
  );

  const renderChart = () => {
    if (!data?.historical?.length) return null;

    const labels = data.historical.map((d) =>
      new Date(d.date).toLocaleDateString("en-IN", {
        month: "short",
        day: "numeric"
      })
    );
    const prices = data.historical.map((d) => d.price);

    return (
      <motion.div
        style={chartCard}
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
      >
        <h3 style={chartTitle}>
          📈 {data.symbol} Price Chart
        </h3>
        <Line
          data={{
            labels,
            datasets: [
              {
                label: "Closing Price",
                data: prices,
                borderColor: "#0ef0ad",
                backgroundColor: "rgba(14, 240, 173, 0.1)",
                fill: true,
                tension: 0.3
              }
            ]
          }}
          options={{
            plugins: { legend: { display: false } },
            scales: {
              x: { ticks: { color: "#aaa" } },
              y: { ticks: { color: "#aaa" } }
            }
          }}
        />
      </motion.div>
    );
  };

  const renderRevenueProfit = () => {
    if (!data?.profitLoss?.length) return null;

    const years = data.profitLoss.map((d) => d.year);
    const revenue = data.profitLoss.map((d) => d.revenue);
    const profit = data.profitLoss.map((d) => d.profit);

    return (
      <motion.div
        style={chartCard}
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
      >
        <h3 style={chartTitle}>💰 Revenue & Profit</h3>
        <Bar
          data={{
            labels: years,
            datasets: [
              {
                label: "Revenue",
                data: revenue,
                backgroundColor: "rgba(54,162,235,0.6)"
              },
              {
                label: "Profit",
                data: profit,
                backgroundColor: "rgba(255,99,132,0.6)"
              }
            ]
          }}
          options={{
            plugins: {
              legend: { labels: { color: "#aaa" } }
            },
            scales: {
              x: { ticks: { color: "#aaa" } },
              y: { ticks: { color: "#aaa" } }
            }
          }}
        />
      </motion.div>
    );
  };

  return (
    <motion.div
      style={pageStyle}
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
    >
      <h2 style={headingStyle}>
        Indian Stock Details
      </h2>

      <div style={searchContainer}>
        <input
          value={symbol}
          onChange={(e) => setSymbol(e.target.value)}
          placeholder="Enter symbol (e.g. TCS.NS)"
          style={inputStyle}
        />
        <motion.button
          style={buttonStyle}
          onClick={fetchData}
          whileHover={{ scale: 1.05 }}
          disabled={loading}
        >
          {loading ? "Loading..." : "Get Data"}
        </motion.button>
      </div>

      {error && (
        <p style={{ color: "red" }}>{error}</p>
      )}

      {data && (
        <>
          <h3 style={stockTitle}>
            {data.name} ({data.symbol})
          </h3>
          <h1
            style={{
              color:
                data.change > 0 ? "#28a745" : "#dc3545"
            }}
          >
            ₹{formatNumber(data.price)} | Change:{" "}
            {formatNumber(data.change)} (
            {formatNumber(data.percentChange)}%)
          </h1>

          <motion.div
            style={metricsGrid}
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
          >
            {metricList.map((m) =>
              renderMetric(
                m.label,
                data[m.key],
                m.currency
              )
            )}
          </motion.div>

          {renderChart()}

          {renderRevenueProfit()}

          <AffiliateBanner />

          <div style={{ marginTop: "30px" }}>
            <a
              href="https://www.buymeacoffee.com/yourusername"
              target="_blank"
              rel="noreferrer"
              style={{
                display: "inline-block",
                background: "#FFDD00",
                color: "#000",
                padding: "12px 24px",
                borderRadius: "6px",
                textDecoration: "none",
                fontWeight: "bold"
              }}
            >
              ☕ Buy me a Coffee
            </a>
          </div>
        </>
      )}
    </motion.div>
  );
};

export default INDStockDetails;

// STYLES

const pageStyle = {
  maxWidth: "1200px",
  margin: "60px auto",
  background: "#0e1c2f",
  padding: "2rem",
  borderRadius: "12px",
  color: "#f0f2f5",
  fontFamily: "Segoe UI, sans-serif"
};

const headingStyle = {
  color: "#0ef0ad",
  fontSize: "2.5rem",
  textAlign: "center",
  marginBottom: "2rem",
  fontWeight: 700
};

const searchContainer = {
  display: "flex",
  marginBottom: "2rem"
};

const inputStyle = {
  flex: 1,
  padding: "12px",
  fontSize: "1rem",
  borderRadius: "6px",
  border: "1px solid #0ef0ad",
  background: "#121212",
  color: "#f0f2f5"
};

const buttonStyle = {
  background: "#0ef0ad",
  color: "#0e1c2f",
  border: "none",
  padding: "12px 24px",
  borderRadius: "6px",
  cursor: "pointer",
  fontWeight: "bold",
  fontSize: "1rem",
  marginLeft: "1rem"
};

const stockTitle = {
  fontSize: "2rem",
  color: "#0ef0ad",
  margin: "20px 0"
};

const metricsGrid = {
  display: "grid",
  gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))",
  gap: "1rem",
  margin: "30px 0"
};

const metricCard = {
  background: "rgba(255,255,255,0.05)",
  border: "1px solid rgba(255,255,255,0.1)",
  padding: "1rem",
  borderRadius: "8px",
  textAlign: "center"
};

const metricLabel = {
  fontSize: "0.9rem",
  color: "#aaa"
};

const metricValue = {
  fontSize: "1.2rem",
  color: "#f0f2f5",
  fontWeight: "bold"
};

const chartCard = {
  marginTop: "2rem",
  background: "rgba(255,255,255,0.04)",
  padding: "1.5rem",
  borderRadius: "8px"
};

const chartTitle = {
  color: "#0ef0ad",
  marginBottom: "1rem",
  fontSize: "1.3rem"
};
